<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }

body {
    background-color: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
}

#game-container { text-align: center; }

h1 { font-size: 3em; margin-bottom: 20px; color: #f9d476; }

#score {
    font-size: 1.5em;
    margin-bottom: 20px;
    padding: 10px 20px;
    background-color: #16213e;
    border-radius: 8px;
    display: inline-block;
}

#board {
    display: grid;
    grid-template-columns: repeat(4, 100px);
    grid-template-rows: repeat(4, 100px);
    gap: 10px;
    margin-bottom: 20px;
}

.cell {
    background-color: #0f3460;
    border-radius: 8px;
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 1.5em;
    font-weight: bold;
}

.tile {
    width: 90px;
    height: 90px;
    border-radius: 6px;
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 1.5em;
    font-weight: bold;
}

.tile-2 { background-color: #eee4da; color: #776e65; }
.tile-4 { background-color: #ede0c8; color: #776e65; }
.tile-8 { background-color: #f2b179; color: #f9f6f2; }
.tile-16 { background-color: #f59563; color: #f9f6f2; }
.tile-32 { background-color: #f67c5f; color: #f9f6f2; }
.tile-64 { background-color: #f65e3b; color: #f9f6f2; }
.tile-128 { background-color: #edcf72; color: #f9f6f2; }
.tile-256 { background-color: #edcc61; color: #f9f6f2; }
.tile-512 { background-color: #edc850; color: #f9f6f2; }
.tile-1024 { background-color: #edc53f; color: #f9f6f2; }
.tile-2048 { background-color: #edc22e; color: #f9f6f2; }

#reset {
    padding: 12px 30px;
    font-size: 1.2em;
    background-color: #f9d476;
    color: #1a1a2e;
    border: none;
    border-radius: 8px;
    cursor: pointer;
}

#reset:hover { background-color: #f5c550; }
</style>
</head>
<body>
<div id="game-container">
<h1>2048</h1>
<div id="score">Score: 0</div>
<div id="board"></div>
<button id="reset">New Game</button>
</div>

<script>
const SIZE = 4;

function tileClass(value) {
    return 'tile-' + (value <= 2048 ? value : 2048);
}

let state = [];
let score = 0;

function initBoard() {
    state = Array.from({length: SIZE}, () => new Array(SIZE).fill(0));
    render();
}

function render() {
    const boardEl = document.getElementById('board');
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
        for (let c = 0; c < SIZE; c++) {
            let cell = document.createElement('div');
            cell.className = 'cell';
            if (state[r][c] !== 0) {
                let tile = document.createElement('div');
                tile.className = 'tile ' + tileClass(state[r][c]);
                tile.textContent = state[r][c];
                cell.appendChild(tile);
            }
            boardEl.appendChild(cell);
        }
    }
}

function slideLeft(row) {
    let tiles = row.filter(x => x !== 0);
    let result = [];
    for (let i = 0; i < tiles.length; ) {
        if (i + 1 < tiles.length && tiles[i] === tiles[i+1]) {
            result.push(tiles[i] * 2);
            score += tiles[i] * 2;
            i += 2;
        } else {
            result.push(tiles[i]);
            i++;
        }
    }
    while (result.length < SIZE) result.push(0);
    return result;
}

function transpose(board) {
    let result = Array.from({length: SIZE}, (_, c) =>
        [0, 0, 0, 0].map((_, r) => board[r][c])
    );
    return result;
}

function move(direction) {
    let oldState = JSON.stringify(state);

    if (direction === 'left') {
        for (let r = 0; r < SIZE; r++) state[r] = slideLeft(state[r]);
    } else if (direction === 'right') {
        for (let r = 0; r < SIZE; r++) {
            let rev = [...state[r]].reverse();
            state[r] = slideLeft(rev).reverse();
        }
    } else if (direction === 'up') {
        let t = transpose(state);
        for (let r = 0; r < SIZE; r++) t[r] = slideLeft(t[r]);
        for (let r = 0; r < SIZE; r++)
            for (let c = 0; c < SIZE; c++) state[c][r] = t[r][c];
    } else if (direction === 'down') {
        let t = transpose(state);
        for (let r = 0; r < SIZE; r++) {
            t[r] = [...t[r]].reverse();
            t[r] = slideLeft(t[r]);
            t[r] = t[r].reverse();
        }
        for (let r = 0; r < SIZE; r++)
            for (let c = 0; c < SIZE; c++) state[c][r] = t[r][c];
    }

    let newState = JSON.stringify(state);
    if (oldState !== newState) {
        spawnNewTile();
        render();
        return true;
    }
    return false;
}

function spawnNewTile() {
    let empties = [];
    for (let r = 0; r < SIZE; r++)
        for (let c = 0; c < SIZE; c++)
            if (state[r][c] === 0) empties.push({r, c});
    if (empties.length > 0) {
        let pos = empties[Math.floor(Math.random() * empties.length)];
        state[pos.r][pos.c] = Math.random() < 0.9 ? 2 : 4;
    }
}

function getBoard() { return JSON.parse(JSON.stringify(state)); }

function setBoard(arr) {
    for (let r = 0; r < SIZE; r++)
        for (let c = 0; c < SIZE; c++)
            state[r][c] = arr[r] && arr[r][c] !== undefined ? arr[r][c] : 0;
}

function getScore() { return score; }

function resetGame() {
    initBoard();
    spawnNewTile();
    spawnNewTile();
    render();
    document.getElementById('score').textContent = 'Score: ' + score;
}

window.game = {
    size: SIZE,
    reset: resetGame,
    move: move,
    board: getBoard,
    setBoard: setBoard,
    score: getScore
};

document.addEventListener('keydown', (e) => {
    if (['ArrowLeft','ArrowRight','ArrowUp','ArrowDown'].includes(e.key)) {
        e.preventDefault();
        let dir;
        switch (e.key) {
            case 'ArrowLeft': dir = 'left'; break;
            case 'ArrowRight': dir = 'right'; break;
            case 'ArrowUp': dir = 'up'; break;
            case 'ArrowDown': dir = 'down'; break;
        }
        if (move(dir)) document.getElementById('score').textContent = 'Score: ' + score;
    }
});

document.getElementById('reset').addEventListener('click', resetGame);
initBoard();
</script>
</body>
</html>
